query:
query jam($id: String!) {
  jam(id: $id) {
    ... on BaseJam {
      ...Jam
      aiGeneratedFields
      trackedFeaturesUsed
      folder {
        id
        name
      }
      recordingLink {
        publicId
        recordingUrl
        description
        reference
      }
    }
  }
}

fragment Jam on Jam {
  ... on ScreenshotJam {
    ...ScreenshotJam
  }
  ... on VideoJam {
    ...VideoJam
  }
  ... on ReplayJam {
    ...ReplayJam
  }
  ... on InvalidJam {
    ...BaseJam
  }
}

fragment ScreenshotJam on ScreenshotJam {
  ...BaseJam
  data {
    id
    type
    delayMs
    media {
      ...Media
    }
    secondaryMedia {
      ...Media
    }
  }
}

fragment BaseJam on BaseJam {
  __typename
  id
  type
  origin
  originalUrl
  country
  timezoneLocation
  createdAt
  updatedAt
  author {
    ...JamAuthor
  }
  team {
    id
    name
    emoji
    type
  }
  systemInfo {
    browser {
      name
      version
    }
    os {
      name
      version
    }
    screenDimensions {
      width
      height
    }
    extension {
      version
    }
    other {
      key
      value
    }
    battery {
      charging
      level
    }
  }
  detectedLibs {
    logrocket {
      installed
      sessionURL
    }
    sentry {
      installed
      environment
    }
  }
  title
  description
  isIncognito
  fullStoryUrl
  logRocketUrl
  privacyRule {
    ...PrivacyRule
  }
  comments {
    ...Comment
  }
  integrations {
    ...JamIntegration
  }
  events {
    ...Media
  }
  recordingLink {
    publicId
    recordingUrl
    description
    metadata
  }
  recorderFacets {
    recorderSessionId
    integrationName
    workspaceId
    conversationId
    contactId
    contactEmail
    agentName
    agentAvatar
  }
  folder {
    id
    name
  }
}

fragment JamAuthor on JamAuthor {
  id
  name
  firstName
  lastName
  email
  avatarSrc
  avatar
  verifiedAccount
  createdAt
  updatedAt
}

fragment PrivacyRule on PrivacyRule {
  objectId
  objectType
  policy
  domains
  emails
}

fragment Comment on JamComment {
  __typename
  id: uid
  uid
  messageInFormat(format: ProseMirror)
  threadUid
  createdAt
  updatedAt
  edited
  deleted
  playbackRelativeTimestamp
  reactions {
    ...Reaction
  }
  attachments {
    id
    name
    type
    size
    source
  }
  author {
    id
    name
    firstName
    lastName
    email
    avatarSrc
    authorType
  }
}

fragment Reaction on Reaction {
  id
  emoji
  upvotedUsers {
    id
    name
    firstName
    lastName
  }
}

fragment JamIntegration on JamIntegration {
  id
  name
  displayName
  status
  url
  objectId
  objectIdAlias
  openJamOnCreate
  fields {
    key
    label
    value {
      ... on IntegrationStringValue {
        type
        value
      }
      ... on IntegrationLabeledStringValue {
        type
        labeledValue {
          label
          value
        }
      }
      ... on IntegrationLabeledListValue {
        type
        labeledValues {
          label
          value
        }
      }
    }
  }
  events {
    type
    message
    occuredAt
    actor {
      ... on IntegrationActorJamUser {
        type
        userId
        data {
          id
          name
          firstName
          lastName
          email
        }
      }
      ... on IntegrationActorSystem {
        type
        service
      }
      ... on IntegrationActorRecorderAgent {
        type
        agentId
        data {
          id
          name
          avatarSrc
        }
      }
    }
  }
}

fragment Media on Media {
  id
  status
  contentType
  sizeBytes
  url
  createdAt
  updatedAt
}

fragment VideoJam on VideoJam {
  ...BaseJam
  data {
    id
    height
    width
    viewport
    durationMs
    isTrimmed
    micEnabled
    media {
      ...Media
    }
    posterImageMedia {
      ...Media
    }
    cloudflareStream {
      id
      status
    }
  }
}

fragment ReplayJam on ReplayJam {
  ...BaseJam
  data {
    id
    durationMs
    media {
      ...Media
    }
    screenshotMedia {
      ...Media
    }
  }
}
